        name = row[0]
        if name not in names:
            names.append(name)
            subjects.append(row[1:])
        else:
            subjects[-1].append(row[1:])

    # Group subjects by name
    name_subjects = {name: subjects[i] for i, name in enumerate(names)}

    # Create output rows
    output = []
    for name, subjects_list in name_subjects.items():
        for i in range(len(subjects_list)):
            output.append([name] + subjects_list[i])

    return output

